const today = new Date();
const endDate = new Date();
endDate.setDate(endDate.getDate() + 7);

const formatDate = (d) => d.toISOString().split('T')[0];

return [{ json: { start_date: formatDate(today), end_date: formatDate(endDate) } }];

const data = $input.first().json;
const events = data.events || [];

// Group by date
const byDate = {};
events.forEach(e => {
  if (!byDate[e.date]) byDate[e.date] = [];
  byDate[e.date].push(e);
});

let summary = '📅 CALENDARIO DE PICKUPS - Próximos 7 días\n\n';
Object.keys(byDate).sort().forEach(date => {
  summary += `📆 ${date}\n`;
  byDate[date].forEach(e => {
    summary += `   🕐 ${e.time || 'TBD'} - ${e.title}\n`;
    if (e.location) summary += `      📍 ${e.location}\n`;
  });
  summary += '\n';
});

if (events.length === 0) {
  summary += 'No hay pickups programados.\n';
}

return [{ json: { subject: `📅 Calendario VFL - ${events.length} pickups próximos`, body: summary, count: events.length, events } }];
